#include "biblia.h"

void Biblia::CarregarColossenses(Biblia* b) {
    b->dados[COLOSSENSES].nome = wxT("Colossenses");

    b->dados[COLOSSENSES].capitulos[1].versos[1] = wxT("Paulo, apóstolo de Cristo Jesus pela vontade de Deus, e o irmão Timóteo,");
    b->dados[COLOSSENSES].capitulos[1].versos[2] = wxT("aos santos e fiéis irmãos em Cristo que estão em Colossos: Graças a vós, e paz da parte de Deus nosso Pai.");
    b->dados[COLOSSENSES].capitulos[1].versos[3] = wxT("Graças damos a Deus, Pai de nosso Senhor Jesus Cristo, orando sempre por vós,");
    b->dados[COLOSSENSES].capitulos[1].versos[4] = wxT("desde que ouvimos falar da vossa fé em Cristo Jesus, e do amor que tendes a todos os santos,");
    b->dados[COLOSSENSES].capitulos[1].versos[5] = wxT("por causa da esperança que vos está reservada nos céus, da qual antes ouvistes pela palavra da verdade do evangelho,");
    b->dados[COLOSSENSES].capitulos[1].versos[6] = wxT("que já chegou a vós, como também está em todo o mundo, frutificando e crescendo, assim como entre vós desde o dia em que ouvistes e conhecestes a graça de Deus em verdade,");
    b->dados[COLOSSENSES].capitulos[1].versos[7] = wxT("segundo aprendestes de Epafras, nosso amado conservo, que por nós é fiel ministro de Cristo.");
    b->dados[COLOSSENSES].capitulos[1].versos[8] = wxT("O qual também nos declarou o vosso amor no Espírito.");
    b->dados[COLOSSENSES].capitulos[1].versos[9] = wxT("Por esta razão, nós também, desde o dia em que ouvimos, não cessamos de orar por vós, e de pedir que sejais cheios do pleno conhecimento da sua vontade, em toda a sabedoria e entendimento espiritual;");
    b->dados[COLOSSENSES].capitulos[1].versos[10] = wxT("para que possais andar de maneira digna do Senhor, agradando-lhe em tudo, frutificando em toda boa obra, e crescendo no conhecimento de Deus,");
    b->dados[COLOSSENSES].capitulos[1].versos[11] = wxT("corroborados com toda a fortaleza, segundo o poder da sua glória, para toda a perseverança e longanimidade com gozo;");
    b->dados[COLOSSENSES].capitulos[1].versos[12] = wxT("dando graças ao Pai que vos fez idôneos para participar da herança dos santos na luz,");
    b->dados[COLOSSENSES].capitulos[1].versos[13] = wxT("e que nos tirou do poder das trevas, e nos transportou para o reino do seu Filho amado;");
    b->dados[COLOSSENSES].capitulos[1].versos[14] = wxT("em quem temos a redenção, a saber, a remissão dos pecados;");
    b->dados[COLOSSENSES].capitulos[1].versos[15] = wxT("o qual é imagem do Deus invisível, o primogênito de toda a criação;");
    b->dados[COLOSSENSES].capitulos[1].versos[16] = wxT("porque nele foram criadas todas as coisas nos céus e na terra, as visíveis e as invisíveis, sejam tronos, sejam dominações, sejam principados, sejam potestades; tudo foi criado por ele e para ele.");
    b->dados[COLOSSENSES].capitulos[1].versos[17] = wxT("Ele é antes de todas as coisas, e nele subsistem todas as coisas;");
    b->dados[COLOSSENSES].capitulos[1].versos[18] = wxT("também ele é a cabeça do corpo, da igreja; é o princípio, o primogênito dentre os mortos, para que em tudo tenha a preeminência,");
    b->dados[COLOSSENSES].capitulos[1].versos[19] = wxT("porque aprouve a Deus que nele habitasse toda a plenitude,");
    b->dados[COLOSSENSES].capitulos[1].versos[20] = wxT("e que, havendo por ele feito a paz pelo sangue da sua cruz, por meio dele reconciliasse consigo mesmo todas as coisas, tanto as que estão na terra como as que estão nos céus.");
    b->dados[COLOSSENSES].capitulos[1].versos[21] = wxT("A vós também, que outrora éreis estranhos, e inimigos no entendimento pelas vossas obras más,");
    b->dados[COLOSSENSES].capitulos[1].versos[22] = wxT("agora contudo vos reconciliou no corpo da sua carne, pela morte, a fim de perante ele vos apresentar santos, sem defeito e irrepreensíveis,");
    b->dados[COLOSSENSES].capitulos[1].versos[23] = wxT("se é que permaneceis na fé, fundados e firmes, não vos deixando apartar da esperança do evangelho que ouvistes, e que foi pregado a toda criatura que há debaixo do céu, e do qual eu, Paulo, fui constituído ministro.");
    b->dados[COLOSSENSES].capitulos[1].versos[24] = wxT("Agora me regozijo no meio dos meus sofrimentos por vós, e cumpro na minha carne o que resta das aflições de Cristo, por amor do seu corpo, que é a igreja;");
    b->dados[COLOSSENSES].capitulos[1].versos[25] = wxT("da qual eu fui constituído ministro segundo a dispensação de Deus, que me foi concedida para convosco, a fim de cumprir a palavra de Deus,");
    b->dados[COLOSSENSES].capitulos[1].versos[26] = wxT("o mistério que esteve oculto dos séculos, e das gerações; mas agora foi manifesto aos seus santos,");
    b->dados[COLOSSENSES].capitulos[1].versos[27] = wxT("a quem Deus quis fazer conhecer quais são as riquezas da glória deste mistério entre os gentios, que é Cristo em vós, a esperança da glória;");
    b->dados[COLOSSENSES].capitulos[1].versos[28] = wxT("o qual nós anunciamos, admoestando a todo homem, e ensinando a todo homem em toda a sabedoria, para que apresentemos todo homem perfeito em Cristo;");
    b->dados[COLOSSENSES].capitulos[1].versos[29] = wxT("para isso também trabalho, lutando segundo a sua eficácia, que opera em mim poderosamente.");

    b->dados[COLOSSENSES].capitulos[2].versos[1] = wxT("Pois quero que saibais quão grande luta tenho por vós, e pelos que estão em Laodicéia, e por quantos não viram a minha pessoa;");
    b->dados[COLOSSENSES].capitulos[2].versos[2] = wxT("para que os seus corações sejam animados, estando unidos em amor, e enriquecidos da plenitude do entendimento para o pleno conhecimento do mistério de Deus-Cristo,");
    b->dados[COLOSSENSES].capitulos[2].versos[3] = wxT("no qual estão escondidos todos os tesouros da sabedoria e da ciência.");
    b->dados[COLOSSENSES].capitulos[2].versos[4] = wxT("Digo isto, para que ninguém vos engane com palavras persuasivas.");
    b->dados[COLOSSENSES].capitulos[2].versos[5] = wxT("Porque ainda que eu esteja ausente quanto ao corpo, contudo em espírito estou convosco, regozijando-me, e vendo a vossa ordem e a firmeza da vossa fé em Cristo.");
    b->dados[COLOSSENSES].capitulos[2].versos[6] = wxT("Portanto, assim como recebestes a Cristo Jesus, o Senhor, assim também nele andai,");
    b->dados[COLOSSENSES].capitulos[2].versos[7] = wxT("arraigados e edificados nele, e confirmados na fé, assim como fostes ensinados, abundando em ação de graças.");
    b->dados[COLOSSENSES].capitulos[2].versos[8] = wxT("Tendo cuidado para que ninguém vos faça presa sua, por meio de filosofias e vãs sutilezas, segundo a tradição dos homens, segundo os rudimentos do mundo, e não segundo Cristo;");
    b->dados[COLOSSENSES].capitulos[2].versos[9] = wxT("porque nele habita corporalmente toda a plenitude da divindade,");
    b->dados[COLOSSENSES].capitulos[2].versos[10] = wxT("e tendes a vossa plenitude nele, que é a cabeça de todo principado e potestade,");
    b->dados[COLOSSENSES].capitulos[2].versos[11] = wxT("no qual também fostes circuncidados com a circuncisão não feita por mãos no despojar do corpo da carne, a saber, a circuncisão de Cristo;");
    b->dados[COLOSSENSES].capitulos[2].versos[12] = wxT("tendo sido sepultados com ele no batismo, no qual também fostes ressuscitados pela fé no poder de Deus, que o ressuscitou dentre os mortos;");
    b->dados[COLOSSENSES].capitulos[2].versos[13] = wxT("e a vós, quando estáveis mortos nos vossos delitos e na incircuncisão da vossa carne, vos vivificou juntamente com ele, perdoando-nos todos os delitos;");
    b->dados[COLOSSENSES].capitulos[2].versos[14] = wxT("e havendo riscado o escrito de dívida que havia contra nós nas suas ordenanças, o qual nos era contrário, removeu-o do meio de nós, cravando-o na cruz;");
    b->dados[COLOSSENSES].capitulos[2].versos[15] = wxT("e, tendo despojado os principados e potestades, os exibiu publicamente e deles triunfou na mesma cruz.");
    b->dados[COLOSSENSES].capitulos[2].versos[16] = wxT("Ninguém, pois, vos julgue pelo comer, ou pelo beber, ou por causa de dias de festa, ou de lua nova, ou de sábados,");
    b->dados[COLOSSENSES].capitulos[2].versos[17] = wxT("que são sombras das coisas vindouras; mas o corpo é de Cristo.");
    b->dados[COLOSSENSES].capitulos[2].versos[18] = wxT("Ninguém atue como árbitro contra vós, afetando humildade ou culto aos anjos, firmando-se em coisas que tenha visto, inchado vãmente pelo seu entendimento carnal,");
    b->dados[COLOSSENSES].capitulos[2].versos[19] = wxT("e não retendo a Cabeça, da qual todo o corpo, provido e organizado pelas juntas e ligaduras, vai crescendo com o aumento concedido por Deus.");
    b->dados[COLOSSENSES].capitulos[2].versos[20] = wxT("Se morrestes com Cristo quanto aos rudimentos do mundo, por que vos sujeitais ainda a ordenanças, como se vivêsseis no mundo,");
    b->dados[COLOSSENSES].capitulos[2].versos[21] = wxT("tais como: não toques, não proves, não manuseies");
    b->dados[COLOSSENSES].capitulos[2].versos[22] = wxT("{as quais coisas todas hão de perecer pelo uso}, segundo os preceitos e doutrinas dos homens?");
    b->dados[COLOSSENSES].capitulos[2].versos[23] = wxT("As quais têm, na verdade, alguma aparência de sabedoria em culto voluntário, humildade fingida, e severidade para com o corpo, mas não têm valor algum no combate contra a satisfação da carne.");

    b->dados[COLOSSENSES].capitulos[3].versos[1] = wxT("Se, pois, fostes ressuscitados juntamente com Cristo, buscai as coisas que são de cima, onde Cristo está assentado à destra de Deus.");
    b->dados[COLOSSENSES].capitulos[3].versos[2] = wxT("Pensai nas coisas que são de cima, e não nas que são da terra;");
    b->dados[COLOSSENSES].capitulos[3].versos[3] = wxT("porque morrestes, e a vossa vida está escondida com Cristo em Deus.");
    b->dados[COLOSSENSES].capitulos[3].versos[4] = wxT("Quando Cristo, que é a nossa vida, se manifestar, então também vós vos manifestareis com ele em glória.");
    b->dados[COLOSSENSES].capitulos[3].versos[5] = wxT("Exterminai, pois, as vossas inclinações carnais; a prostituição, a impureza, a paixão, a vil concupiscência, e a avareza, que é idolatria;");
    b->dados[COLOSSENSES].capitulos[3].versos[6] = wxT("pelas quais coisas vem a ira de Deus sobre os filhos da desobediência;");
    b->dados[COLOSSENSES].capitulos[3].versos[7] = wxT("nas quais também em outro tempo andastes, quando vivíeis nelas;");
    b->dados[COLOSSENSES].capitulos[3].versos[8] = wxT("mas agora despojai-vos também de tudo isto: da ira, da cólera, da malícia, da maledicência, das palavras torpes da vossa boca;");
    b->dados[COLOSSENSES].capitulos[3].versos[9] = wxT("não mintais uns aos outros, pois que já vos despistes do homem velho com os seus feitos,");
    b->dados[COLOSSENSES].capitulos[3].versos[10] = wxT("e vos vestistes do novo, que se renova para o pleno conhecimento, segundo a imagem daquele que o criou;");
    b->dados[COLOSSENSES].capitulos[3].versos[11] = wxT("onde não há grego nem judeu, circuncisão nem incircuncisão, bárbaro, cita, escravo ou livre, mas Cristo é tudo em todos.");
    b->dados[COLOSSENSES].capitulos[3].versos[12] = wxT("Revestí-vos, pois, como eleitos de Deus, santos e amados, de coração compassivo, de benignidade, humildade, mansidão, longanimidade,");
    b->dados[COLOSSENSES].capitulos[3].versos[13] = wxT("suportando-vos e perdoando-vos uns aos outros, se alguém tiver queixa contra outro; assim como o Senhor vos perdoou, assim fazei vós também.");
    b->dados[COLOSSENSES].capitulos[3].versos[14] = wxT("E, sobre tudo isto, revestí-vos do amor, que é o vínculo da perfeição.");
    b->dados[COLOSSENSES].capitulos[3].versos[15] = wxT("E a paz de Cristo, para a qual também fostes chamados em um corpo, domine em vossos corações; e sede agradecidos.");
    b->dados[COLOSSENSES].capitulos[3].versos[16] = wxT("A palavra de Cristo habite em vós ricamente, em toda a sabedoria; ensinai-vos e admoestai-vos uns aos outros, com salmos, hinos e cânticos espirituais, louvando a Deus com gratidão em vossos corações.");
    b->dados[COLOSSENSES].capitulos[3].versos[17] = wxT("E tudo quanto fizerdes por palavras ou por obras, fazei-o em nome do Senhor Jesus, dando por ele graças a Deus Pai.");
    b->dados[COLOSSENSES].capitulos[3].versos[18] = wxT("Vós, mulheres, sede submissas a vossos maridos, como convém no Senhor.");
    b->dados[COLOSSENSES].capitulos[3].versos[19] = wxT("Vós, maridos, amai a vossas mulheres, e não as trateis asperamente.");
    b->dados[COLOSSENSES].capitulos[3].versos[20] = wxT("Vós, filhos, obedecei em tudo a vossos pais; porque isto é agradável ao Senhor.");
    b->dados[COLOSSENSES].capitulos[3].versos[21] = wxT("Vós, pais, não irriteis a vossos filhos, para que não fiquem desanimados.");
    b->dados[COLOSSENSES].capitulos[3].versos[22] = wxT("Vós, servos, obedecei em tudo a vossos senhores segundo a carne, não servindo somente à vista como para agradar aos homens, mas em singeleza de coração, temendo ao Senhor.");
    b->dados[COLOSSENSES].capitulos[3].versos[23] = wxT("E tudo quanto fizerdes, fazei-o de coração, como ao Senhor, e não aos homens,");
    b->dados[COLOSSENSES].capitulos[3].versos[24] = wxT("sabendo que do Senhor recebereis como recompensa a herança; servi a Cristo, o Senhor.");
    b->dados[COLOSSENSES].capitulos[3].versos[25] = wxT("Pois quem faz injustiça receberá a paga da injustiça que fez; e não há acepção de pessoas.");

    b->dados[COLOSSENSES].capitulos[4].versos[1] = wxT("Vós, senhores, dai a vossos servos o que é de justiça e eqüidade, sabendo que também vós tendes um Senhor no céu.");
    b->dados[COLOSSENSES].capitulos[4].versos[2] = wxT("Perseverai na oração, velando nela com ações de graças,");
    b->dados[COLOSSENSES].capitulos[4].versos[3] = wxT("orando ao mesmo tempo também por nós, para que Deus nos abra uma porta à palavra, a fim de falarmos o mistério de Cristo, pelo qual também estou preso,");
    b->dados[COLOSSENSES].capitulos[4].versos[4] = wxT("para que eu o manifeste como devo falar.");
    b->dados[COLOSSENSES].capitulos[4].versos[5] = wxT("Andai em sabedoria para com os que estão de fora, usando bem cada oportunidade.");
    b->dados[COLOSSENSES].capitulos[4].versos[6] = wxT("A vossa palavra seja sempre com graça, temperada com sal, para saberdes como deveis responder a cada um.");
    b->dados[COLOSSENSES].capitulos[4].versos[7] = wxT("Tíquico, o irmão amado, fiel ministro e conservo no Senhor, vos fará conhecer a minha situação;");
    b->dados[COLOSSENSES].capitulos[4].versos[8] = wxT("o qual vos envio para este mesmo fim, para que saibais o nosso estado e ele conforte os vossos corações,");
    b->dados[COLOSSENSES].capitulos[4].versos[9] = wxT("juntamente com Onésimo, fiel e amado irmão, que é um de vós; eles vos farão saber tudo o que aqui se passa.");
    b->dados[COLOSSENSES].capitulos[4].versos[10] = wxT("Saúda-vos Aristarco, meu companheiro de prisão, e Marcos, o primo de Barnabé {a respeito do qual recebestes instruções; se for ter convosco, recebei-o},");
    b->dados[COLOSSENSES].capitulos[4].versos[11] = wxT("e Jesus, que se chama Justo, sendo unicamente estes, dentre a circuncisão, os meus cooperadores no reino de Deus; os quais têm sido para mim uma consolação.");
    b->dados[COLOSSENSES].capitulos[4].versos[12] = wxT("Saúda-vos Epafras, que é um de vós, servo de Cristo Jesus, e que sempre luta por vós nas suas orações, para que permaneçais perfeitos e plenamente seguros em toda a vontade de Deus.");
    b->dados[COLOSSENSES].capitulos[4].versos[13] = wxT("Pois dou-lhe testemunho de que tem grande zelo por vós, como também pelos que estão em Laodicéia, e pelos que estão em Hierápolis.");
    b->dados[COLOSSENSES].capitulos[4].versos[14] = wxT("Saúda-vos Lucas, o médico amado, e Demas.");
    b->dados[COLOSSENSES].capitulos[4].versos[15] = wxT("Saudai aos irmãos que estão em Laodicéia, e a Ninfas e a igreja que está em sua casa.");
    b->dados[COLOSSENSES].capitulos[4].versos[16] = wxT("Depois que for lida esta carta entre vós, fazei que o seja também na igreja dos laodicenses; e a de Laodicéia lede-a vós também.");
    b->dados[COLOSSENSES].capitulos[4].versos[17] = wxT("E dizei a Arquipo: Cuida do ministério que recebestes no Senhor, para o cumprires.");
    b->dados[COLOSSENSES].capitulos[4].versos[18] = wxT("Esta saudação é de próprio punho, de Paulo. Lembrai-vos das minhas cadeias. A graça seja convosco.");

}
